import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const rootDir = path.dirname(fileURLToPath(import.meta.url));
const out = path.join(rootDir, 'dev_level.json');
const mat = (baseColorMapRef, extra = {}) => ({ baseColorMapRef, ...extra });
const box = (id, position, scale, tex, extra = {}) => ({
  id,
  type: 'box',
  position,
  scale,
  materials: [mat(tex, extra.material || {})],
  ...Object.fromEntries(Object.entries(extra).filter(([key]) => key !== 'material')),
});
const light = (id, position, color, intensity, distance, decay, extra = {}) => ({
  id,
  type: 'point',
  position,
  color,
  intensity,
  distance,
  decay,
  ...extra,
});
const panel = (id, position, rotation, title, lines, interactLabel, interactText, extra = {}) => ({
  id,
  template: 'info_panel_base',
  position,
  rotation,
  title,
  lines,
  interactLabel,
  interactText,
  ...extra,
});

